const base64String = $input.first().json.data;
const sizeKB = Math.round(base64String.length / 1024);

if (base64String.length > 800000) {
  throw new Error(`CV too large: ${sizeKB}KB. Please use a PDF under 600KB.`);
}

return [{
  json: {
    base64: base64String,
    sizeKB: sizeKB
  }
}];

// 1. Get data from the previous nodes
const extraction = $node["easybits: Extract CV Data"].json.data;
// We use the first item from Airtable (index 0)
const job = $node["Airtable - Fetch Open Job"].json; 

// Combine everything the CV parser found into one text block
const cvText = JSON.stringify(extraction).toLowerCase();

// 2. Score against the TECH STACK instead of the long phrases
// This list has "Python", "Figma", "Clay", etc.
const techRequirements = job.tech_stack || [];

let matches = 0;
let foundItems = [];

techRequirements.forEach(skill => {
  // Clean up the skill name and check if it's in the CV
  const cleanSkill = skill.toLowerCase().trim();
  if (cvText.includes(cleanSkill)) {
    matches++;
    foundItems.push(skill);
  }
});

// 3. Calculate Score
const total = techRequirements.length || 1;
const finalScore = Math.round((matches / total) * 100);

return {
  match_score: finalScore,
  matched_count: matches,
  total_possible: total,
  details: foundItems.join(", "),
  name: extraction.candidate_name || "Jordan Reed",
  email: extraction.contact_email || "N/A",
  linkedin: extraction.linkedin_url || "N/A"
};

